import React, { useState } from "react";
import "./addcourse.css";
import Navbar from "../components/navbar";
import axios from "axios";

function AddCourse() {
  const navigate=useNavigate()
  const [courseName, setCourseName] = useState("");
  const [courseCode, setCourseCode] = useState("");
  const [instructor, setInstructor] = useState("");
  const [credits, setCredits] = useState("");

  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const res = await axios.post("http://localhost:5000/addcourse", {
        courseName,
        courseCode,
        instructor,
        credits
      });

      alert("✅ " + res.data.message);
      console.log(res.data)

      // Reset form
      setCourseName("");
      setCourseCode("");
      setInstructor("");
      setCredits("");
      navigate("/register-course")
    } catch (err) {
      console.error("Error adding course:", err.response?.data || err);
      alert(err.response?.data?.message || "Error adding course");
    }
  };

  return (
    <>
      <Navbar />
      <form className="course-form" onSubmit={handleSubmit}>
        <label>Course Name</label>
        <input type="text" value={courseName} onChange={(e) => setCourseName(e.target.value)} required />

        <label>Course Code</label>
        <input type="text" value={courseCode} onChange={(e) => setCourseCode(e.target.value)} required />

        <label>Instructor</label>
        <input type="text" value={instructor} onChange={(e) => setInstructor(e.target.value)} required />

        <label>Credits</label>
        <input type="number" value={credits} onChange={(e) => setCredits(e.target.value)} required />

        <button type="submit">Add Course</button>
      </form>
    </>
  );
}

export default AddCourse;
